CustomField.formula:
IF(
    AND(
        /* --- 1. FILTROS DUROS DE RIESGO --- */

        /* Validar que el campo fecha no esté vacío por seguridad y calcular edad (18 a 65) */
        NOT(ISBLANK(Fecha_de_nacimiento__c)),
        (TODAY() - Fecha_de_nacimiento__c) / 365.2425 >= 18,
        (TODAY() - Fecha_de_nacimiento__c) / 365.2425 <= 65,

        /* Validar que la Situación Laboral sea aceptada */
        OR(
            TEXT(Situacion_Laboral__c) = "Dependiente",
            TEXT(Situacion_Laboral__c) = "Independiente",
            TEXT(Situacion_Laboral__c) = "Empresario"
        ),

        /* --- 2. MATRIZ COMERCIAL DE PRODUCTOS --- */
        OR(
            /* 1. Regla para Visa Light */
            AND(
                TEXT(Segmento_de_Tarjeta__c) = "Light",
                TEXT(Tipo_de_Tarjeta__c) = "Visa",
                Ingreso_Mensual__c >= 1000,
                Ingreso_Mensual__c < 2000,
                Linea_de_Credito_Solicitada__c <= 1500
            ),

            /* 2. Regla para Clásica (Visa/Amex) y Standard (Mastercard) */
            AND(
                OR(
                    AND(TEXT(Segmento_de_Tarjeta__c) = "Clásica", OR(TEXT(Tipo_de_Tarjeta__c) = "Visa", TEXT(Tipo_de_Tarjeta__c) = "Amex")),
                    AND(TEXT(Segmento_de_Tarjeta__c) = "Standard", TEXT(Tipo_de_Tarjeta__c) = "Mastercard")
                ),
                Ingreso_Mensual__c >= 2000,
                Ingreso_Mensual__c < 3500,
                Linea_de_Credito_Solicitada__c <= 3000
            ),

            /* 3. Regla para Oro (Aplica igual para Visa, Amex, Mastercard) */
            AND(
                TEXT(Segmento_de_Tarjeta__c) = "Oro",
                Ingreso_Mensual__c >= 3500,
                Ingreso_Mensual__c < 5500,
                Linea_de_Credito_Solicitada__c <= 5000
            ),

            /* 4. Regla para Platinum (Aplica igual para Visa, Amex, Mastercard) */
            AND(
                TEXT(Segmento_de_Tarjeta__c) = "Platinum",
                Ingreso_Mensual__c >= 5500,
                Ingreso_Mensual__c < 7500,
                Linea_de_Credito_Solicitada__c <= 7000
            ),

            /* 5. Regla para Visa Signature */
            AND(
                TEXT(Segmento_de_Tarjeta__c) = "Signature",
                TEXT(Tipo_de_Tarjeta__c) = "Visa",
                Ingreso_Mensual__c >= 7500,
                Ingreso_Mensual__c < 10000,
                Linea_de_Credito_Solicitada__c <= 10000
            ),

            /* 6. Regla para Top Tier: Infinite (Visa) y Black (Amex) */
            AND(
                OR(
                    AND(TEXT(Segmento_de_Tarjeta__c) = "Infinite", TEXT(Tipo_de_Tarjeta__c) = "Visa"),
                    AND(TEXT(Segmento_de_Tarjeta__c) = "Black", TEXT(Tipo_de_Tarjeta__c) = "Amex")
                ),
                Ingreso_Mensual__c >= 10000,
                Linea_de_Credito_Solicitada__c > 10000
            )
        )
    ),
    "Sí",
    "No"
)
